import { HTMLAttributes, forwardRef } from "react";
import { Slot, cn, swirskiAttrs } from "../../system";

export type AlertTone = "blue" | "yellow" | "red" | "white";
export type AlertVariant = "solid" | "outline" | "soft";
export type AlertSize = "sm" | "md" | "lg";

export type AlertProps = {
  asChild?: boolean;
  variant?: AlertVariant;
  size?: AlertSize;
  tone?: AlertTone;
} & HTMLAttributes<HTMLDivElement>;

const toneStyles: Record<AlertTone, string> = {
  blue: "bg-[var(--sw-color-blue)] text-white",
  yellow: "bg-[var(--sw-color-yellow)] text-[var(--sw-color-ink)]",
  red: "bg-[var(--sw-color-red)] text-white",
  white: "bg-[var(--sw-color-surface)] text-[var(--sw-color-ink)]",
};

const outlineToneStyles: Record<AlertTone, string> = {
  blue: "bg-[var(--sw-color-surface)] text-[var(--sw-color-blue)]",
  yellow: "bg-[var(--sw-color-surface)] text-[var(--sw-color-ink)]",
  red: "bg-[var(--sw-color-surface)] text-[var(--sw-color-red)]",
  white: "bg-transparent text-[var(--sw-color-surface)] border-[color:var(--sw-color-surface)]",
};

const softToneStyles: Record<AlertTone, string> = {
  blue: "bg-[var(--sw-color-blue)]/10 text-[var(--sw-color-ink)]",
  yellow: "bg-[var(--sw-color-yellow)]/30 text-[var(--sw-color-ink)]",
  red: "bg-[var(--sw-color-red)]/10 text-[var(--sw-color-ink)]",
  white: "bg-[var(--sw-color-surface)]/20 text-[var(--sw-color-surface)]",
};

const sizeStyles: Record<AlertSize, string> = {
  sm: "p-4",
  md: "p-5",
  lg: "p-6",
};

export const Alert = forwardRef<HTMLDivElement, AlertProps>(function Alert({
  asChild = false,
  variant = "solid",
  size = "md",
  tone = "yellow",
  className,
  children,
  role = "status",
  ...props
}, ref) {
  const Component = asChild ? Slot : "div";

  return (
    <Component
      ref={ref}
      role={role}
      className={cn(
        "border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] shadow-[var(--sw-shadow-md)]",
        sizeStyles[size],
        variant === "solid" && toneStyles[tone],
        variant === "outline" && outlineToneStyles[tone],
        variant === "soft" && softToneStyles[tone],
        className,
      )}
      {...swirskiAttrs("alert", { size, tone, variant })}
      {...props}
    >
      {children}
    </Component>
  );
});

Alert.displayName = "Alert";

import { HTMLAttributes, forwardRef } from "react";
import { cn, swirskiAttrs } from "../../system";

export type AlertDescriptionVariant = "default";
export type AlertDescriptionSize = "sm" | "md" | "lg";
export type AlertDescriptionTone = "default";

export type AlertDescriptionProps = {
  variant?: AlertDescriptionVariant;
  size?: AlertDescriptionSize;
  tone?: AlertDescriptionTone;
} & HTMLAttributes<HTMLParagraphElement>;

const sizeStyles: Record<AlertDescriptionSize, string> = {
  sm: "text-xs leading-5",
  md: "text-sm leading-6",
  lg: "text-base leading-7",
};

export const AlertDescription = forwardRef<
  HTMLParagraphElement,
  AlertDescriptionProps
>(function AlertDescription(
  { className, variant = "default", size = "md", tone = "default", ...props },
  ref,
) {
  return (
    <p
      ref={ref}
      className={cn("mt-3 font-bold", sizeStyles[size], className)}
      {...swirskiAttrs("alert-description", { size, tone, variant })}
      {...props}
    />
  );
});

AlertDescription.displayName = "AlertDescription";

import { HTMLAttributes, forwardRef } from "react";
import { cn, swirskiAttrs } from "../../system";

export type AlertTitleVariant = "default";
export type AlertTitleSize = "sm" | "md" | "lg";
export type AlertTitleTone = "default";

export type AlertTitleProps = {
  variant?: AlertTitleVariant;
  size?: AlertTitleSize;
  tone?: AlertTitleTone;
} & HTMLAttributes<HTMLHeadingElement>;

const sizeStyles: Record<AlertTitleSize, string> = {
  sm: "text-xl",
  md: "text-2xl",
  lg: "text-3xl",
};

export const AlertTitle = forwardRef<HTMLHeadingElement, AlertTitleProps>(
  function AlertTitle(
    { className, variant = "default", size = "md", tone = "default", ...props },
    ref,
  ) {
    return (
      <h3
        ref={ref}
        className={cn("font-anton uppercase leading-none", sizeStyles[size], className)}
        {...swirskiAttrs("alert-title", { size, tone, variant })}
        {...props}
      />
    );
  },
);

AlertTitle.displayName = "AlertTitle";

export { Alert } from "./Alert";
export { AlertTitle } from "./AlertTitle";
export { AlertDescription } from "./AlertDescription";
export type { AlertProps, AlertSize, AlertTone, AlertVariant } from "./Alert";
export type {
  AlertDescriptionProps,
  AlertDescriptionSize,
  AlertDescriptionTone,
  AlertDescriptionVariant,
} from "./AlertDescription";
export type {
  AlertTitleProps,
  AlertTitleSize,
  AlertTitleTone,
  AlertTitleVariant,
} from "./AlertTitle";
